-- flashcards-specific settings
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_title', 'My Study Cards', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_description', 'Flashcards for active recall and spaced repetition', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Write the question or prompt on the front. Keep it short enough to read at a glance in the card grid. Use the pattern: [Term] — [brief hint]."},"content":{"tips":"Write the answer for the back of the card. Be concise but complete. One clear idea per card works best for retention."},"formatting":["Bold: highlight the key term or answer within the explanation","Code blocks: formulas, equations, and code snippets","Numbered lists: step-by-step processes or sequences","Bullet lists: multiple related facts or properties","Tables: comparisons between similar concepts","Blockquotes: mnemonics or memory aids"],"avoid":["Cramming multiple concepts onto a single card","Vague fronts that could match many answers","Walls of text that defeat quick-recall purpose"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":5,"max":200},"content":{"min":1,"max":5000},"sourceAi":{"min":1,"max":100}}', datetime('now'));
